1	/**
2	 * Client-side AI engine for BYOK (Bring Your Own Key).
3	 *
4	 * This module runs AI calls entirely in the browser using the Vercel AI SDK
5	 * and the provider packages bundled with the app. Provider API keys are read
6	 * from the caller's `AiSettings` object (stored in IndexedDB only). They are
7	 * never sent to any server.
8	 *
9	 * The prompt builders from `convex/agentPrompts.ts` are reused so the voices
10	 * stay identical whether the call runs client-side or server-side.
11	 *
12	 * Usage:
13	 *   const result = await runClientAgent("persona-feedback", agentRequest, settings);
14	 *   if (result) { use it } else { fallback to Convex action }
15	 */
16	
17	import { generateText, type LanguageModel } from "ai";
18	import type {
19	  AiSettings,
20	  AiFeature,
21	  AiProviderConfig,
22	  AiFeatureOverride,
23	} from "../types";
24	import type {
25	  AgentRequest,
26	  AgentResponse,
27	  FeedbackType,
28	} from "../../convex/agentPrompts";
29	import { buildSystemPrompt, buildUserPrompt } from "../../convex/agentPrompts";
30	import {
31	  localAiBaseUrl,
32	  LOCAL_MODEL_ID,
33	  LOCAL_PROVIDER_ID,
34	} from "./desktop-bridge";
35	import { captureAiGeneration } from "./ai-evals";
36	import { stripReasoningTags } from "./reasoning-tags";
37	
38	/* ── Provider factory ───────────────────────────────────────────── */
39	
40	function isOpenAiCompatibleProvider(type: AiProviderConfig["type"]): boolean {
41	  return (
42	    type === "openai-compatible" ||
43	    type === "deepseek" ||
44	    type === "openrouter" ||
45	    type === "ollama" ||
46	    type === "zai" ||
47	    type === "minimax"
48	  );
49	}
50	
51	async function createModel(
52	  config: AiProviderConfig,
53	  modelOverride?: string,
54	): Promise<LanguageModel | null> {
55	  try {
56	    const modelId =
57	      modelOverride || config.defaultModel || config.availableModels?.[0] || "";
58	    if (!modelId) return null;
59	    switch (config.type) {
60	      case "openai": {
61	        const { createOpenAI } = await import("@ai-sdk/openai");
62	        const openai = createOpenAI({ apiKey: config.apiKey });
63	        return openai.chat(modelId);
64	      }
65	      case "anthropic": {
66	        const { createAnthropic } = await import("@ai-sdk/anthropic");
67	        const anthropicProvider = createAnthropic({ apiKey: config.apiKey });
68	        return anthropicProvider.chat(modelId);
69	      }
70	      case "anthropic-compatible": {
71	        const { createAnthropic } = await import("@ai-sdk/anthropic");
72	        const anthropicProvider = createAnthropic({
73	          apiKey: config.apiKey,
74	          baseURL: config.baseUrl,
75	        });
76	        return anthropicProvider.chat(modelId);
77	      }
78	      case "google": {
79	        const { createGoogleGenerativeAI } = await import("@ai-sdk/google");
80	        const googleProvider = createGoogleGenerativeAI({
81	          apiKey: config.apiKey,
82	        });
83	        return googleProvider(modelId);
84	      }
85	      case "openai-compatible": {
86	        const { createOpenAI } = await import("@ai-sdk/openai");
87	        const openai = createOpenAI({
88	          apiKey: config.apiKey,
89	          baseURL: config.baseUrl,
90	        });
91	        return openai.chat(modelId);
92	      }
93	      case "deepseek":
94	      case "openrouter":
95	      case "ollama":
96	      case "zai":
97	      case "minimax": {
98	        const { createOpenAI } = await import("@ai-sdk/openai");
99	        const openai = createOpenAI({
100	          apiKey: config.apiKey || "local",
101	          baseURL: config.baseUrl,
102	        });
103	        return openai.chat(modelId);
104	      }
105	      case "litert": {
106	        // Desktop-only native model exposed as an OpenAI-compatible server on
107	        // loopback by the Electrobun shell. No real key; baseUrl is the local
108	        // endpoint discovered from the desktop bridge.
109	        const { createOpenAI } = await import("@ai-sdk/openai");
110	        const openai = createOpenAI({
111	          apiKey: config.apiKey || "local",
112	          baseURL: config.baseUrl,
113	        });
114	        return openai.chat(modelId);
115	      }
116	      default:
117	        return null;
118	    }
119	  } catch (err) {
120	    console.warn("[twyne:ai-client] failed to create model:", err);
121	    return null;
122	  }
123	}
124	
125	/* ── Feature routing ────────────────────────────────────────────── */
126	
127	/**
128	 * Resolve the effective provider + model + params for a feature.
129	 * Falls back to the global default provider when a feature has no override.
130	 */
131	export function resolveFeatureConfig(
132	  settings: AiSettings,
133	  feature: AiFeature,
134	): {
135	  provider: AiProviderConfig;
136	  model: string;
137	  temperature: number;
138	  maxTokens: number;
139	} | null {
140	  const normalized = normalizeAiSettings(settings);
141	  if (normalized.providers.length === 0) {
142	    return null;
143	  }
144	
145	  const override: AiFeatureOverride | undefined =
146	    normalized.perFeature[feature];
147	  const providerId =
148	    override?.providerId ??
149	    normalized.defaultProviderId ??
150	    normalized.providers[0]?.id;
151	  if (!providerId) return null;
152	
153	  const provider = normalized.providers.find((p) => p.id === providerId);
154	  if (!provider) return null;
155	
156	  return {
157	    provider,
158	    model: override?.model ?? defaultModelForFeature(feature, provider),
159	    temperature: override?.temperature ?? defaultTemperature(feature),
160	    maxTokens: override?.maxTokens ?? defaultMaxTokens(feature),
161	  };
162	}
163	
164	export function hasConfiguredAiProvider(
165	  settings: Partial<AiSettings> | AiSettings | null | undefined,
166	): boolean {
167	  if (!settings) return false;
168	  return normalizeAiSettings(settings).providers.length > 0;
169	}
170	
171	function defaultModelForFeature(
172	  feature: AiFeature,
173	  provider: AiProviderConfig,
174	): string {
175	  if (
176	    feature === "voice-narration" &&
177	    (provider.type === "openai" || isOpenAiCompatibleProvider(provider.type))
178	  ) {
179	    return "gpt-4o-mini-tts";
180	  }
181	  return provider.defaultModel;
182	}
183	
184	function defaultTemperature(feature: AiFeature): number {
185	  switch (feature) {
186	    case "rubric-judge":
187	      return 0.2;
188	    case "voice-narration":
189	      return 0.4;
190	    case "citation-format":
191	      return 0.1;
192	    case "source-summarize":
193	      return 0.3;
194	    case "source-detect-missing":
195	      return 0.2;
196	    default:
197	      return 0.4;
198	  }
199	}
200	
201	function defaultMaxTokens(feature: AiFeature): number {
202	  switch (feature) {
203	    case "persona-feedback":
204	      return 380;
205	    case "persona-reply":
206	      return 320;
207	    case "persona-rewrite":
208	      return 320;
209	    case "rubric-judge":
210	      return 220;
211	    case "voice-narration":
212	      return 0;
213	    case "comment-reply":
214	      return 280;
215	    case "citation-format":
216	      return 180;
217	    case "source-summarize":
218	      return 200;
219	    case "source-detect-missing":
220	      return 350;
221	    default:
222	      return 300;
223	  }
224	}
225	
226	/* ── Public: generate speech client-side (BYOK) ─────────────────── */
227	
228	export interface VoiceSpeechRequest {
229	  text: string;
230	  voice?: string;
231	  instructions?: string;
232	  responseFormat?: "mp3" | "opus" | "aac" | "flac" | "wav" | "pcm";
233	  speed?: number;
234	}
235	
236	export interface VoiceSpeechResult {
237	  audio: Blob;
238	  provider: string;
239	  model: string;
240	  voice: string;
241	  responseFormat: string;
242	}
243	
244	export async function runClientVoiceSpeech(
245	  req: VoiceSpeechRequest,
246	  settings: AiSettings,
247	): Promise<VoiceSpeechResult | null> {
248	  const resolved = resolveFeatureConfig(settings, "voice-narration");
249	  if (!resolved) return null;
250	  if (
251	    resolved.provider.type !== "openai" &&
252	    !isOpenAiCompatibleProvider(resolved.provider.type)
253	  ) {
254	    console.warn(
255	      "[twyne:ai-client] voice narration requires an OpenAI or OpenAI-compatible provider.",
256	    );
257	    return null;
258	  }
259	
260	  const input = req.text.trim().slice(0, 4096);
261	  if (!input) return null;
262	
263	  const override = settings.perFeature["voice-narration"];
264	  const voice = req.voice ?? override?.voice ?? "alloy";
265	  const responseFormat =
266	    req.responseFormat ?? override?.responseFormat ?? "mp3";
267	  const speed = req.speed ?? override?.speed;
268	  const instructions = req.instructions ?? override?.instructions;
269	  const baseURL =
270	    isOpenAiCompatibleProvider(resolved.provider.type) &&
271	    resolved.provider.baseUrl
272	      ? resolved.provider.baseUrl.replace(/\/$/, "")
273	      : "https://api.openai.com/v1";
274	
275	  try {
276	    const res = await fetch(`${baseURL}/audio/speech`, {
277	      method: "POST",
278	      headers: {
279	        authorization: `Bearer ${resolved.provider.apiKey}`,
280	        "content-type": "application/json",
281	      },
282	      body: JSON.stringify({
283	        model: resolved.model,
284	        input,
285	        voice,
286	        response_format: responseFormat,
287	        ...(instructions ? { instructions } : {}),
288	        ...(speed ? { speed } : {}),
289	      }),
290	    });
291	    if (!res.ok) {
292	      const detail = await res.text().catch(() => "");
293	      throw new Error(
294	        `Voice generation failed (${res.status}): ${detail.slice(0, 240)}`,
295	      );
296	    }
297	    const audio = new Blob([await res.arrayBuffer()], {
298	      type: audioMimeType(responseFormat),
299	    });
300	    return {
301	      audio,
302	      provider: resolved.provider.type,
303	      model: resolved.model,
304	      voice,
305	      responseFormat,
306	    };
307	  } catch (err) {
308	    console.warn("[twyne:ai-client] voice narration failed:", err);
309	    return null;
310	  }
311	}
312	
313	function audioMimeType(format: string): string {
314	  switch (format) {
315	    case "opus":
316	      return "audio/opus";
317	    case "aac":
318	      return "audio/aac";
319	    case "flac":
320	      return "audio/flac";
321	    case "wav":
322	      return "audio/wav";
323	    case "pcm":
324	      return "audio/L16";
325	    case "mp3":
326	    default:
327	      return "audio/mpeg";
328	  }
329	}
330	
331	async function generateTrackedText({
332	  feature,
333	  resolved,
334	  model,
335	  system,
336	  prompt,
337	  spanName,
338	  evalSignals,
339	}: {
340	  feature: AiFeature;
341	  resolved: {
342	    provider: AiProviderConfig;
343	    model: string;
344	    temperature: number;
345	    maxTokens: number;
346	  };
347	  model: LanguageModel;
348	  system?: string;
349	  prompt: string;
350	  spanName?: string;
351	  evalSignals?: Record<string, unknown>;
352	}): Promise<string> {
353	  const start = performance.now();
354	  try {
355	    const { text } = await generateText({
356	      model,
357	      system,
358	      prompt,
359	      temperature: resolved.temperature,
360	      maxOutputTokens: resolved.maxTokens,
361	    });
362	    const cleaned = stripReasoningTags(text);
363	    await captureAiGeneration({
364	      feature,
365	      provider: resolved.provider.type,
366	      model: resolved.model,
367	      system,
368	      prompt,
369	      output: cleaned,
370	      latencyMs: performance.now() - start,
371	      temperature: resolved.temperature,
372	      maxTokens: resolved.maxTokens,
373	      spanName,
374	      evalSignals,
375	    });
376	    return cleaned;
377	  } catch (err) {
378	    await captureAiGeneration({
379	      feature,
380	      provider: resolved.provider.type,
381	      model: resolved.model,
382	      system,
383	      prompt,
384	      latencyMs: performance.now() - start,
385	      temperature: resolved.temperature,
386	      maxTokens: resolved.maxTokens,
387	      spanName,
388	      error: err,
389	      evalSignals,
390	    });
391	    throw err;
392	  }
393	}
394	
395	/* ── Classification (mirrors convex/agents.ts) ──────────────────── */
396	
397	const typeKeywords: Record<FeedbackType, RegExp> = {
398	  encouragement: /\b(protect|strength|alive|good|works|love|keep)\b/i,
399	  suggestion: /\b(try|consider|suggest|add|cut|move|compress|split|drop)\b/i,
400	  critique:
401	    /\b(weak|fail|missing|wrong|load[- ]bearing|unstated|evade|counterpoint|reject)\b/i,
402	  perspective:
403	    /\b(as a|reader|audience|expect|signal|outcome|trust|confused|won over)\b/i,
404	};
405	
406	const typeOrder: FeedbackType[] = [
407	  "critique",
408	  "suggestion",
409	  "encouragement",
410	  "perspective",
411	];
412	
413	function classifyType(text: string, fallback: FeedbackType): FeedbackType {
414	  const scores = typeOrder.map((t) => ({
415	    t,
416	    score: (text.match(typeKeywords[t]) ?? []).length,
417	  }));
418	  scores.sort((a, b) => b.score - a.score);
419	  if (scores[0]?.score > 0) return scores[0].t;
420	  return fallback;
421	}
422	
423	function defaultTypeForPersona(personaId: string): FeedbackType {
424	  switch (personaId) {
425	    case "devil":
426	      return "critique";
427	    case "angel":
428	      return "encouragement";
429	    case "scholar":
430	    case "editor":
431	      return "suggestion";
432	    case "reader":
433	    default:
434	      return "perspective";
435	  }
436	}
437	
438	/* ── Rewrite response parser (mirrors convex/agents.ts) ─────────── */
439	
440	function parseRewriteOutput(
441	  text: string,
442	): { replacement: string; rationale: string } | null {
443	  const stripped = stripReasoningTags(text)
444	    .trim()
445	    .replace(/^```(?:json)?/i, "")
446	    .replace(/```$/, "")
447	    .trim();
448	  const tryParse = (s: string) => {
449	    try {
450	      const o = JSON.parse(s);
451	      if (o && typeof o.replacement === "string" && o.replacement.trim()) {
452	        return {
453	          replacement: o.replacement.trim(),
454	          rationale: typeof o.rationale === "string" ? o.rationale.trim() : "",
455	        };
456	      }
457	    } catch {
458	      /* fall through */
459	    }
460	    return null;
461	  };
462	  return (
463	    tryParse(stripped) ?? tryParse(stripped.match(/\{[\s\S]*\}/)?.[0] ?? "")
464	  );
465	}
466	
467	/* ── Public: run a rewrite client-side ──────────────────────────── */
468	
469	export interface RewriteClientRequest {
470	  persona: AgentRequest["persona"];
471	  brief: AgentRequest["brief"];
472	  draftText: string;
473	  original: string;
474	  level: "sentence" | "paragraph";
475	}
476	
477	export interface RewriteClientResult {
478	  replacement: string;
479	  rationale: string;
480	  provider: string;
481	}
482	
483	export async function runClientRewrite(
484	  req: RewriteClientRequest,
485	  settings: AiSettings,
486	): Promise<RewriteClientResult | null> {
487	  const resolved = resolveFeatureConfig(settings, "persona-rewrite");
488	  if (!resolved) return null;
489	
490	  const model = await createModel(resolved.provider, resolved.model);
491	  if (!model) return null;
492	
493	  try {
494	    const system = buildSystemPrompt(req.persona);
495	    const sizeRule =
496	      req.level === "sentence"
497	        ? "Keep the replacement to a single sentence."
498	        : "The replacement may be up to one paragraph, but no longer than the original.";
499	    const user = `${buildUserPrompt({
500	      persona: req.persona,
501	      brief: req.brief,
502	      draftText: req.draftText,
503	      instruction: "rewrite-suggestion",
504	    })}
505	
506	REWRITE TASK: Rewrite the PASSAGE below in your voice, preserving its meaning but doing the work better. ${sizeRule}
507	Respond as JSON only, no prose: {"replacement": "<rewritten passage as plain text>", "rationale": "<one sentence, in your voice>"}
508	
509	PASSAGE:
510	"${req.original}"`;
511	
512	    const text = await generateTrackedText({
513	      feature: "persona-rewrite",
514	      resolved,
515	      model,
516	      system,
517	      prompt: user,
518	      spanName: "persona_rewrite",
519	      evalSignals: {
520	        twyne_persona_id: req.persona.id,
521	        twyne_rewrite_level: req.level,
522	      },
523	    });
524	
525	    const parsed = parseRewriteOutput(text);
526	    if (parsed) {
527	      return {
528	        replacement: parsed.replacement,
529	        rationale: parsed.rationale,
530	        provider: resolved.provider.type,
531	      };
532	    }
533	    return null;
534	  } catch (err) {
535	    console.warn("[twyne:ai-client] rewrite failed:", err);
536	    return null;
537	  }
538	}
539	
540	/* ── Public: run an agent client-side ───────────────────────────── */
541	
542	export async function runClientAgent(
543	  feature: AiFeature,
544	  req: AgentRequest,
545	  settings: AiSettings,
546	): Promise<AgentResponse | null> {
