583	/* ── Judge output parser (mirrors convex/agents.ts) ─────────────── */
584	
585	function parseJudgeOutput(
586	  text: string,
587	): { score: number; rationale: string } | null {
588	  const stripped = stripReasoningTags(text)
589	    .replace(/```(?:json)?/gi, "")
590	    .replace(/```/g, "")
591	    .trim();
592	  try {
593	    const obj = JSON.parse(stripped);
594	    if (typeof obj.score === "number" && typeof obj.rationale === "string") {
595	      return { score: clampScore(obj.score), rationale: obj.rationale };
596	    }
597	  } catch {
598	    // fall through
599	  }
600	  const scoreMatch = stripped.match(/"?score"?\s*[:=]\s*(\d+)/i);
601	  const rationaleMatch = stripped.match(/"?rationale"?\s*[:=]\s*"([^"]+)"/i);
602	  if (scoreMatch) {
603	    return {
604	      score: clampScore(parseInt(scoreMatch[1], 10)),
605	      rationale:
606	        rationaleMatch?.[1] ??
607	        "The draft does part of the work and leaves the rest to the writer.",
608	    };
609	  }
610	  return null;
611	}
612	
613	function clampScore(score: number): number {
614	  if (!Number.isFinite(score)) return 5;
615	  return Math.max(1, Math.min(10, Math.round(score)));
616	}
