700	export interface ProviderModelDiscoveryResult {
701	  models: string[];
702	  source: "remote" | "fallback";
703	}
704	
705	function normalizeApiBaseUrl(
706	  baseUrl: string | undefined,
707	  fallback: string,
708	): string {
709	  const raw = baseUrl?.trim() || fallback;
710	  return raw.replace(/\/+$/, "");
711	}
712	
713	function dedupeModels(models: Array<string | null | undefined>): string[] {
714	  return Array.from(
715	    new Set(
716	      models.map((m) => m?.trim()).filter((m): m is string => Boolean(m)),
717	    ),
718	  );
719	}
720	
721	function fallbackModelsForProvider(config: AiProviderConfig): string[] {
722	  return dedupeModels([config.defaultModel, ...(config.availableModels ?? [])]);
723	}
724	
725	export async function discoverProviderModels(
726	  config: AiProviderConfig,
727	): Promise<ProviderModelDiscoveryResult> {
728	  const fallback = fallbackModelsForProvider(config);
729	
730	  try {
731	    if (config.type === "google") {
732	      const res = await fetch(
733	        `https://generativelanguage.googleapis.com/v1beta/models?key=${encodeURIComponent(config.apiKey)}`,
734	      );
735	      if (!res.ok) {
736	        throw new Error(`Model discovery failed (${res.status})`);
737	      }
738	      const body = (await res.json()) as {
739	        models?: Array<{ name?: string; displayName?: string }>;
740	      };
741	      const models = dedupeModels(
742	        (body.models ?? []).flatMap((m) => [
743	          m.name?.replace(/^models\//, ""),
744	          m.displayName,
745	        ]),
746	      );
747	      return {
748	        models: models.length > 0 ? models : fallback,
749	        source: models.length > 0 ? "remote" : "fallback",
750	      };
751	    }
752	
753	    const isAnthropicStyle =
754	      config.type === "anthropic" || config.type === "anthropic-compatible";
755	    const baseUrl = normalizeApiBaseUrl(
756	      config.baseUrl,
757	      isAnthropicStyle
758	        ? "https://api.anthropic.com/v1"
759	        : "https://api.openai.com/v1",
760	    );
761	    const headers: Record<string, string> = isAnthropicStyle
762	      ? {
763	          "x-api-key": config.apiKey,
764	          "anthropic-version": "2023-06-01",
765	        }
766	      : config.apiKey && config.type !== "ollama"
767	        ? {
768	            authorization: `Bearer ${config.apiKey}`,
769	          }
770	        : {};
771	
772	    const res = await fetch(`${baseUrl}/models`, { headers });
773	    if (!res.ok) {
774	      throw new Error(`Model discovery failed (${res.status})`);
775	    }
776	
777	    const body = (await res.json()) as {
778	      data?: Array<{ id?: string; name?: string }>;
779	      models?: Array<{ id?: string; name?: string; displayName?: string }>;
780	    };
781	
782	    const models = dedupeModels([
783	      ...(body.data ?? []).flatMap((m) => [m.id, m.name]),
784	      ...(body.models ?? []).flatMap((m) => [m.id, m.name, m.displayName]),
785	    ]);
786	
787	    return {
788	      models: models.length > 0 ? models : fallback,
789	      source: models.length > 0 ? "remote" : "fallback",
790	    };
791	  } catch (err) {
792	    const message = (err as Error)?.message ?? "Model discovery failed";
793	    if (fallback.length > 0) {
794	      return { models: fallback, source: "fallback" };
795	    }
796	    throw new Error(message);
797	  }
798	}
