1115	  const defaultProviderId =
1116	    settings.defaultProviderId === LOCAL_PROVIDER_ID
1117	      ? (providers[0]?.id ?? null)
1118	      : settings.defaultProviderId;
1119	  const perFeature = Object.fromEntries(
1120	    Object.entries(settings.perFeature).filter(
1121	      ([, override]) => override?.providerId !== LOCAL_PROVIDER_ID,
