1152	  const providers = settings.providers.some((p) => p.id === LOCAL_PROVIDER_ID)
1153	    ? settings.providers.map((p) => (p.id === LOCAL_PROVIDER_ID ? local : p))
1154	    : [...settings.providers, local];
