1208	      confidence: Partial<
1209	        Record<keyof ProjectInterviewAnswers, InterviewConfidence>
1210	      >;
1211	      provider: string;
1212	      model: string;
1213	    };
1214	
1215	const INTERVIEW_FIELDS = [
1216	  "workingTitle",
1217	  "format",
1218	  "audience",
1219	  "goal",
1220	  "tone",
1221	  "constraints",
1222	  "successSignal",
1223	] as const satisfies ReadonlyArray<keyof ProjectInterviewAnswers>;
1224	
1225	function extractTaggedJson(
1226	  text: string,
1227	  tag: "DOSSIER" | "SYNTHESIZE",
1228	): { value: unknown; start: number; end: number } | null {
1229	  const marker = new RegExp(`${tag}:`, "i").exec(text);
1230	  if (!marker) return null;
1231	  const open = text.indexOf("{", marker.index + marker[0].length);
1232	  if (open < 0) return null;
1233	
1234	  let depth = 0;
1235	  let inString = false;
1236	  let escaped = false;
1237	  for (let i = open; i < text.length; i += 1) {
1238	    const ch = text[i];
1239	    if (escaped) {
1240	      escaped = false;
1241	      continue;
1242	    }
1243	    if (ch === "\\") {
1244	      escaped = true;
1245	      continue;
1246	    }
1247	    if (ch === '"') {
1248	      inString = !inString;
1249	      continue;
1250	    }
1251	    if (inString) continue;
1252	    if (ch === "{") depth += 1;
1253	    if (ch === "}") {
1254	      depth -= 1;
1255	      if (depth === 0) {
1256	        try {
1257	          return {
1258	            value: JSON.parse(text.slice(open, i + 1)),
1259	            start: marker.index,
1260	            end: i + 1,
1261	          };
1262	        } catch {
1263	          return null;
1264	        }
1265	      }
1266	    }
1267	  }
1268	  return null;
1269	}
1270	
1271	function normalizeInterviewDossierDraft(
1272	  value: unknown,
1273	): InterviewDossierDraft | null {
1274	  if (!value || typeof value !== "object") return null;
1275	  const obj = value as Record<string, unknown>;
1276	  const briefSource =
1277	    obj.brief && typeof obj.brief === "object"
1278	      ? (obj.brief as Record<string, unknown>)
1279	      : obj;
1280	  const confidenceSource =
1281	    obj.confidence && typeof obj.confidence === "object"
1282	      ? (obj.confidence as Record<string, unknown>)
1283	      : {};
1284	
1285	  const brief: Partial<ProjectInterviewAnswers> = {};
1286	  const confidence: Partial<
1287	    Record<keyof ProjectInterviewAnswers, InterviewConfidence>
1288	  > = {};
1289	  for (const field of INTERVIEW_FIELDS) {
1290	    const raw = briefSource[field];
1291	    if (typeof raw === "string" && raw.trim()) {
1292	      brief[field] = raw.trim();
1293	    }
1294	    const c = confidenceSource[field];
1295	    if (c === "high" || c === "medium" || c === "low") {
1296	      confidence[field] = c;
1297	    }
1298	  }
1299	  return Object.keys(brief).length > 0 ? { brief, confidence } : null;
1300	}
1301	
1302	function stripTaggedJson(
1303	  text: string,
1304	  segment: { start: number; end: number },
1305	) {
1306	  return `${text.slice(0, segment.start)}${text.slice(segment.end)}`.trim();
1307	}
1308	
1309	/**
1310	 * Run one conversational-interview turn against the writer's configured
1311	 * provider. Returns null when BYOK is off / no providers — the caller
1312	 * is expected to fall back to the form-based `AntiTabulaRasa`.
1313	 */
1314	export async function runClientInterviewTurn(
1315	  request: InterviewTurnRequest,
1316	  settings: AiSettings,
1317	): Promise<InterviewTurnResult | null> {
1318	  const cfg = resolveFeatureConfig(settings, "interview-turn");
1319	  if (!cfg) return null;
1320	  const model = await createModel(cfg.provider, cfg.model);
1321	  if (!model) return null;
1322	  try {
1323	    const lastUser = [...request.messages]
1324	      .reverse()
1325	      .find((m) => m.author === "writer");
1326	    const system = [
1327	      "You are a kind, incisive editorial interviewer helping a writer build a project dossier.",
1328	      "Ask one question at a time. Keep it short. You are building a writer's room: identify the piece, reader, goal, tone, constraints, success signal, and what kind of advisors/editors the writer wants around it.",
1329	      'After every ordinary question, append `DOSSIER:` followed by JSON { "brief": { workingTitle, format, audience, goal, tone, constraints, successSignal }, "confidence": { field: "high" | "medium" | "low" } }. Only include fields you can reasonably infer.',
1330	      "When the dossier is complete enough for review, respond only with `SYNTHESIZE:` followed by the same JSON shape. Put requested advisors/editors into constraints or goal until the product has a dedicated advisor schema.",
1331	      request.mode === "refine" && request.currentBrief
1332	        ? `Existing dossier: ${JSON.stringify(request.currentBrief.answers)} — refine it, don't restart.`
1333	        : "",
1334	    ]
1335	      .filter(Boolean)
1336	      .join("\n");
1337	    const transcript = request.messages
1338	      .map((m) => `${m.author === "writer" ? "Writer" : "You"}: ${m.text}`)
1339	      .join("\n");
1340	    const text = await generateTrackedText({
1341	      feature: "interview-turn",
1342	      resolved: cfg,
1343	      model,
1344	      system,
1345	      prompt: transcript,
1346	      spanName: "interview_turn",
1347	      evalSignals: {
1348	        twyne_interview_mode: request.mode,
1349	        twyne_message_count: request.messages.length,
1350	      },
1351	    });
1352	    const synthSegment = extractTaggedJson(text, "SYNTHESIZE");
1353	    if (synthSegment) {
1354	      const draft = normalizeInterviewDossierDraft(synthSegment.value);
1355	      if (draft) {
1356	        return {
1357	          kind: "synthesis",
1358	          brief: draft.brief as ProjectInterviewAnswers,
1359	          confidence: draft.confidence,
1360	          provider: cfg.provider.name,
1361	          model: cfg.model,
1362	        };
1363	      }
1364	    }
1365	
1366	    // Backward compatibility for the previous two-object SYNTHESIZE format.
1367	    const legacySynthMatch = text.match(
1368	      /SYNTHESIZE:\s*(\{[\s\S]*?\})\s*(\{[\s\S]*?\})?/,
1369	    );
1370	    if (legacySynthMatch) {
1371	      try {
1372	        return {
1373	          kind: "synthesis",
1374	          brief: JSON.parse(legacySynthMatch[1]) as ProjectInterviewAnswers,
1375	          confidence: legacySynthMatch[2]
1376	            ? (JSON.parse(legacySynthMatch[2]) as Partial<
1377	                Record<keyof ProjectInterviewAnswers, InterviewConfidence>
1378	              >)
1379	            : {},
1380	          provider: cfg.provider.name,
1381	          model: cfg.model,
1382	        };
1383	      } catch {
1384	        // Malformed synthesis — fall through to a question reply.
1385	      }
1386	    }
1387	
1388	    const dossierSegment = extractTaggedJson(text, "DOSSIER");
1389	    const draft = dossierSegment
1390	      ? normalizeInterviewDossierDraft(dossierSegment.value)
1391	      : null;
1392	    const reply =
1393	      (dossierSegment ? stripTaggedJson(text, dossierSegment) : text).trim() ||
1394	      (lastUser ? "Tell me more." : "What is the working title of this piece?");
1395	    return {
1396	      kind: "question",
1397	      text: reply,
1398	      draft: draft ?? undefined,
1399	      provider: cfg.provider.name,
1400	      model: cfg.model,
1401	    };
1402	  } catch (err) {
1403	    console.warn("[twyne:ai-client] interview turn failed:", err);
1404	    return null;
1405	  }
1406	}
1407	
1408	/* ── Dossier check (BYOK) ───────────────────────────────────────── */
1409	
1410	/** Reads a draft against the brief, surfaces drift. */
1411	export interface DossierCheckRequest {
1412	  brief: ProjectBrief;
1413	  draftText: string | null;
1414	}
1415	
1416	/**
1417	 * Runs the "Read my draft" pass — asks the configured provider to
1418	 * compare the draft against the dossier and report fields that have
1419	 * drifted. Returns null when BYOK is off (caller shows the empty state).
1420	 */
1421	export async function runClientDossierCheck(
1422	  request: DossierCheckRequest,
1423	  settings: AiSettings,
1424	): Promise<{
1425	  observations: Array<{
1426	    field: keyof ProjectInterviewAnswers;
1427	    current: string;
1428	    suggested: string;
1429	    reason: string;
1430	  }>;
