1436	  if (!model) return null;
1437	  try {
1438	    const system = [
1439	      "You read a writer's draft against their project dossier.",
1440	      "Identify fields of the dossier that the draft has outgrown or contradicted.",
1441	      "Respond with a JSON object { observations: [{ field, current, suggested, reason }] }.",
1442	      "Valid fields: workingTitle, format, audience, goal, tone, constraints, successSignal.",
1443	      "If the draft is consistent with the dossier, return { observations: [] }.",
1444	    ].join("\n");
1445	    const user = `Dossier: ${JSON.stringify(request.brief.answers)}\n\nDraft:\n${request.draftText ?? "(no draft yet)"}`;
1446	    const text = await generateTrackedText({
1447	      feature: "dossier-check",
