const EXPLICIT_REFERENCE =
  /(?:^|\n)\s*(?:on|passage|line)\s*:\s*["“”']([^"“”'\n]{6,400})["“”']/i;
const QUOTED_PASSAGE = /["“]([^"”\n]{6,400})["”]/g;

export function extractDynamicFeedbackAnchor(
  feedbackText: string,
  draftText: string,
): string | undefined {
  const candidates = [
    EXPLICIT_REFERENCE.exec(feedbackText)?.[1],
    ...Array.from(feedbackText.matchAll(QUOTED_PASSAGE), (m) => m[1]),
  ];

  for (const candidate of candidates) {
    const resolved = resolveDraftPassage(candidate, draftText);
    if (resolved) return resolved;
  }
  return undefined;
}

function resolveDraftPassage(
  quote: string | undefined,
  draftText: string,
): string | undefined {
  const cleaned = quote?.replace(/\s+/g, " ").trim();
  if (!cleaned || cleaned.split(/\s+/).length < 3) return undefined;
  if (draftText.includes(cleaned)) return cleaned;

  const normalizedQuote = normalizeText(cleaned);
  if (!normalizedQuote) return undefined;

  for (const passage of draftPassages(draftText)) {
    const normalizedPassage = normalizeText(passage);
    if (
      normalizedPassage === normalizedQuote ||
      normalizedPassage.includes(normalizedQuote)
    ) {
      return passage;
    }
  }
  return undefined;
}

function draftPassages(draftText: string): string[] {
  const passages: string[] = [];
  for (const paragraph of draftText.split(/\n+/)) {
    const trimmed = paragraph.trim();
    if (!trimmed) continue;
    const sentences = trimmed.match(/[^.!?]+[.!?]+(?=\s|$)/g) ?? [];
    passages.push(...sentences.map((s) => s.trim()));
    passages.push(trimmed);
  }
  return passages;
}

function normalizeText(text: string): string {
  return text
    .toLowerCase()
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/[^a-z0-9'" ]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

