92	  const briefBlock = brief
93	    ? `PROJECT BRIEF (verbatim, do not invent new facts)
94	- Title: ${brief.answers.workingTitle}
95	- Format: ${brief.answers.format}
96	- Audience: ${brief.answers.audience}
97	- Goal: ${brief.answers.goal}
98	- Tone: ${brief.answers.tone}
99	- Constraints: ${brief.answers.constraints}
