1	/**
2	 * Static writing-feature scoring for the galley-proof rubric. The room's
3	 * judges (the personas) do most of the work, but the rubric blends in a
4	 * deterministic feature score so a draft can't game the judges with
5	 * eloquent prose over a hollow structure.
6	 *
7	 * Each feature returns 0-10. The overall static score is a weighted
8	 * mean, deliberately hard — a 7 on this scale means the draft is well
9	 * structured, well-cited, well-paced, and properly scoped.
10	 */
11	
12	import { detectCitations } from "./citations";
13	
14	export interface StaticFeatures {
15	  wordCount: number;
16	  paragraphCount: number;
17	  sentenceCount: number;
18	  avgSentenceLength: number;
19	  sentenceLengthStdDev: number;
20	  citationCount: number;
21	  citationDensity: number; // citations per 1000 words
22	  avgWordLength: number;
23	  uniqueWordsRatio: number; // type-token ratio
24	  shortParagraphRatio: number; // paragraphs with < 40 words
25	  longParagraphRatio: number; // paragraphs with > 220 words
26	  duplicateParagraphRatio: number;
27	  fillerWordRatio: number;
28	  vagueWordRatio: number;
29	  unsupportedUniversalClaimCount: number;
30	}
31	
32	export interface StaticScore {
33	  features: StaticFeatures;
34	  /** Per-feature scores, 0-10. */
35	  perFeature: {
36	    length: number;
37	    structure: number;
38	    pacing: number;
39	    evidence: number;
40	    vocabulary: number;
41	    paragraphShape: number;
42	    integrity: number;
43	  };
44	  /** Weighted mean, 0-10. */
45	  total: number;
46	  feedback: string[];
47	}
48	
49	const FEATURE_WEIGHTS = {
50	  length: 0.1,
51	  structure: 0.15,
52	  pacing: 0.15,
53	  evidence: 0.2,
54	  vocabulary: 0.1,
55	  paragraphShape: 0.1,
56	  integrity: 0.2,
57	} as const;
58	
59	export function scoreStaticFeatures(draftText: string): StaticScore {
60	  const text = draftText.trim();
61	  const features = computeFeatures(text);
62	  const perFeature = {
63	    length: scoreLength(features),
64	    structure: scoreStructure(features),
65	    pacing: scorePacing(features),
66	    evidence: scoreEvidence(features),
67	    vocabulary: scoreVocabulary(features),
68	    paragraphShape: scoreParagraphShape(features),
69	    integrity: scoreIntegrity(features),
70	  };
71	  const total =
72	    perFeature.length * FEATURE_WEIGHTS.length +
73	    perFeature.structure * FEATURE_WEIGHTS.structure +
74	    perFeature.pacing * FEATURE_WEIGHTS.pacing +
75	    perFeature.evidence * FEATURE_WEIGHTS.evidence +
76	    perFeature.vocabulary * FEATURE_WEIGHTS.vocabulary +
77	    perFeature.paragraphShape * FEATURE_WEIGHTS.paragraphShape +
78	    perFeature.integrity * FEATURE_WEIGHTS.integrity;
79	
80	  return {
81	    features,
82	    perFeature,
83	    total,
84	    feedback: buildFeedback(features, perFeature),
85	  };
86	}
87	
88	function computeFeatures(text: string): StaticFeatures {
89	  const words = text.split(/\s+/).filter(Boolean);
90	  const wordCount = words.length;
91	  const paragraphs = text
92	    .split(/\n{2,}/)
93	    .map((p) => p.trim())
94	    .filter(Boolean);
95	  const paragraphCount = paragraphs.length;
96	
97	  const sentences = text
98	    .split(/(?<=[.!?])\s+/)
99	    .map((s) => s.trim())
100	    .filter(Boolean);
101	  const sentenceCount = sentences.length;
102	  const sentenceLengths = sentences.map(
103	    (s) => s.split(/\s+/).filter(Boolean).length,
104	  );
105	  const avgSentenceLength =
106	    sentenceLengths.length > 0
107	      ? sentenceLengths.reduce((a, b) => a + b, 0) / sentenceLengths.length
108	      : 0;
109	  const sentenceLengthStdDev = standardDeviation(sentenceLengths);
110	
111	  const citationCount = detectCitations(text).length;
112	  const citationDensity =
113	    wordCount > 0 ? (citationCount / wordCount) * 1000 : 0;
114	
115	  const avgWordLength =
116	    words.length > 0
117	      ? words.reduce((sum, w) => sum + w.length, 0) / words.length
118	      : 0;
119	  const uniqueWords = new Set(
120	    words.map((w) => w.toLowerCase().replace(/[^a-z']/g, "")),
121	  );
122	  const uniqueWordsRatio =
123	    words.length > 0 ? uniqueWords.size / words.length : 0;
124	
125	  const paragraphLengths = paragraphs.map(
126	    (p) => p.split(/\s+/).filter(Boolean).length,
127	  );
128	  const shortParagraphRatio =
129	    paragraphLengths.length > 0
130	      ? paragraphLengths.filter((n) => n < 40).length / paragraphLengths.length
131	      : 0;
132	  const longParagraphRatio =
133	    paragraphLengths.length > 0
134	      ? paragraphLengths.filter((n) => n > 220).length / paragraphLengths.length
135	      : 0;
136	  const normalizedParagraphs = paragraphs
137	    .map((p) =>
138	      p
139	        .toLowerCase()
140	        .replace(/[^a-z0-9\s]/g, " ")
141	        .replace(/\s+/g, " ")
142	        .trim(),
143	    )
144	    .filter((p) => p.split(/\s+/).length >= 12);
145	  const duplicateParagraphRatio =
146	    normalizedParagraphs.length > 0
147	      ? (normalizedParagraphs.length - new Set(normalizedParagraphs).size) /
148	        normalizedParagraphs.length
149	      : 0;
150	  const fillerMatches = text.match(FILLER_WORDS) ?? [];
151	  const vagueMatches = text.match(VAGUE_WORDS) ?? [];
152	  const fillerWordRatio = wordCount > 0 ? fillerMatches.length / wordCount : 0;
153	  const vagueWordRatio = wordCount > 0 ? vagueMatches.length / wordCount : 0;
154	  const unsupportedUniversalClaimCount = sentences.filter(
155	    (s) => UNIVERSAL_CLAIM.test(s) && !SOURCE_MARKER.test(s),
156	  ).length;
157	
158	  return {
159	    wordCount,
160	    paragraphCount,
161	    sentenceCount,
162	    avgSentenceLength,
163	    sentenceLengthStdDev,
164	    citationCount,
165	    citationDensity,
166	    avgWordLength,
167	    uniqueWordsRatio,
168	    shortParagraphRatio,
169	    longParagraphRatio,
170	    duplicateParagraphRatio,
171	    fillerWordRatio,
172	    vagueWordRatio,
173	    unsupportedUniversalClaimCount,
174	  };
175	}
176	
177	const FILLER_WORDS =
178	  /\b(very|really|basically|actually|literally|simply|clearly|obviously|undeniably|innovative|robust|leverage|synergy|paradigm|game[- ]changer|cutting[- ]edge|seamless|world[- ]class|transformative)\b/gi;
179	const VAGUE_WORDS =
180	  /\b(thing|things|stuff|various|many|some|people|society|important|interesting|significant|impactful|better|worse|good|bad|a lot|kind of|sort of)\b/gi;
181	const UNIVERSAL_CLAIM =
182	  /\b(always|never|everyone|no one|all (?:people|writers|readers|users)|none of|proves?|guarantees?|undeniably|obviously|clearly)\b/i;
183	const SOURCE_MARKER =
184	  /\b(according to|study|studies|research|data|survey|report|census|doi:|https?:\/\/|\(\s*[A-Z][A-Za-z-]+,\s*\d{4}\s*\)|\[\d+\])\b/i;
185	
186	function standardDeviation(values: number[]): number {
187	  if (values.length === 0) return 0;
188	  const mean = values.reduce((a, b) => a + b, 0) / values.length;
189	  const variance =
190	    values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / values.length;
191	  return Math.sqrt(variance);
192	}
193	
194	/* ── Per-feature scorers (0-10, hard) ──────────────────────────── */
195	
196	function scoreLength(f: StaticFeatures): number {
197	  if (f.wordCount < 80) return 1; // not yet a draft
198	  if (f.wordCount < 200) return 3;
199	  if (f.wordCount < 400) return 5;
200	  if (f.wordCount < 800) return 6.5;
201	  if (f.wordCount < 1500) return 7.5;
202	  if (f.wordCount < 3000) return 8;
203	  if (f.wordCount < 6000) return 7.5;
204	  return 6.5; // very long without proportional structure starts to drag
205	}
206	
207	function scoreStructure(f: StaticFeatures): number {
208	  if (f.paragraphCount === 0) return 0;
209	  if (f.paragraphCount < 3) return 3;
210	  if (f.paragraphCount < 6) return 5.5;
211	  if (f.paragraphCount < 10) return 7;
212	  if (f.paragraphCount < 20) return 7.5;
213	  return 6; // too many short paragraphs suggests fragmented thinking
214	}
215	
216	function scorePacing(f: StaticFeatures): number {
217	  if (f.sentenceCount === 0) return 0;
218	  // Best rhythm: avg 12-22 words, std dev 5-10.
219	  const lengthFit = gaussianFit(f.avgSentenceLength, 17, 5);
220	  const varianceFit = gaussianFit(f.sentenceLengthStdDev, 7, 4);
221	  return clamp(0, 10, (lengthFit + varianceFit) * 5);
222	}
223	
224	function scoreEvidence(f: StaticFeatures): number {
225	  if (f.wordCount === 0) return 0;
226	  // Aim for 2-6 citations per 1000 words. Nothing is 0; lots is 9.
227	  if (f.citationDensity < 0.5) return 1;
228	  if (f.citationDensity < 1.5) return 3;
229	  if (f.citationDensity < 3) return 5.5;
230	  if (f.citationDensity < 6) return 7.5;
231	  if (f.citationDensity < 10) return 8;
232	  return 6; // citation stuffing is a smell
233	}
234	
235	function scoreVocabulary(f: StaticFeatures): number {
236	  // Type-token ratio: 0.45-0.6 is healthy; above 0.7 means each word is
237	  // used once, which is bad. Below 0.3 means repetition.
238	  if (f.uniqueWordsRatio < 0.25) return 2;
239	  if (f.uniqueWordsRatio < 0.35) return 4;
240	  if (f.uniqueWordsRatio < 0.5) return 6.5;
241	  if (f.uniqueWordsRatio < 0.6) return 8;
242	  if (f.uniqueWordsRatio < 0.7) return 7;
243	  return 5;
244	}
245	
246	function scoreParagraphShape(f: StaticFeatures): number {
247	  // Penalize both too-short and too-long paragraph dominance.
248	  const shortPenalty = clamp(0, 1, f.shortParagraphRatio * 2);
249	  const longPenalty = clamp(0, 1, f.longParagraphRatio * 2.5);
250	  const score = 10 - shortPenalty * 4 - longPenalty * 5;
251	  return clamp(0, 10, score);
252	}
253	
254	function scoreIntegrity(f: StaticFeatures): number {
255	  let score = 10;
256	  score -= clamp(0, 4, f.duplicateParagraphRatio * 16);
257	  score -= clamp(0, 2.5, f.fillerWordRatio * 90);
258	  score -= clamp(0, 2.5, f.vagueWordRatio * 45);
259	  score -= clamp(0, 4, f.unsupportedUniversalClaimCount * 0.8);
260	  if (f.wordCount < 220) score = Math.min(score, 4);
261	  return clamp(0, 10, score);
262	}
263	
264	/* ── Helpers ──────────────────────────────────────────────────── */
265	
266	function gaussianFit(value: number, mean: number, sigma: number): number {
267	  return Math.exp(-((value - mean) ** 2) / (2 * sigma ** 2));
268	}
269	
270	function clamp(min: number, max: number, value: number): number {
271	  return Math.max(min, Math.min(max, value));
272	}
273	
274	function buildFeedback(
275	  f: StaticFeatures,
276	  s: StaticScore["perFeature"],
277	): string[] {
278	  const out: string[] = [];
279	  if (f.wordCount < 200) {
280	    out.push(
281	      `The draft is short (${f.wordCount} words). Most pieces need at least 400 words before the rubric can be honest.`,
282	    );
283	  }
284	  if (s.evidence < 4) {
285	    out.push(
286	      `Citations are sparse (${f.citationCount} found, ${f.citationDensity.toFixed(
287	        1,
288	      )} per 1,000 words). Claims are not yet supported.`,
289	    );
290	  }
291	  if (s.pacing < 4) {
292	    out.push(
293	      `Sentence pacing is uneven. Average sentence is ${f.avgSentenceLength.toFixed(
294	        1,
295	      )} words; standard deviation ${f.sentenceLengthStdDev.toFixed(
296	        1,
297	      )}. Aim for 12-22 word sentences with healthy variation.`,
298	    );
299	  }
300	  if (s.structure < 4) {
301	    out.push(
302	      `The draft has ${f.paragraphCount} paragraph${f.paragraphCount === 1 ? "" : "s"}. Build a beginning, a turn, and a landing before another pass.`,
303	    );
304	  }
305	  if (f.shortParagraphRatio > 0.5 && f.paragraphCount >= 4) {
306	    out.push(
307	      `Most paragraphs are short. The piece reads as fragments, not as a single argument.`,
308	    );
309	  }
310	  if (f.longParagraphRatio > 0.3) {
311	    out.push(
312	      `Some paragraphs are very long. Split where the topic changes, or where the reader needs a breath.`,
313	    );
314	  }
315	  if (s.vocabulary < 4) {
316	    out.push(
317	      `Vocabulary repetition is high. Find a sharper synonym, or cut the repeated word.`,
318	    );
319	  }
320	  if (s.integrity < 6) {
321	    out.push(
322	      `Bullshit check is low: ${f.unsupportedUniversalClaimCount} unsupported universal claim${
323	        f.unsupportedUniversalClaimCount === 1 ? "" : "s"
324	      }, ${(f.fillerWordRatio * 100).toFixed(1)}% filler, ${(
325	        f.vagueWordRatio * 100
326	      ).toFixed(
327	        1,
328	      )}% vague wording, ${(f.duplicateParagraphRatio * 100).toFixed(0)}% duplicated paragraphs.`,
329	    );
330	  }
331	  if (out.length === 0) {
332	    out.push(
333	      "Static features are within the working range. The judges' verdict will dominate the final grade.",
334	    );
335	  }
336	  return out;
337	}
338	
339	/* ── Combined rubric ──────────────────────────────────────────── */
340	
341	export interface JudgeResult {
342	  personaId: string;
343	  score: number;
344	  rationale: string;
345	  provider: string;
346	}
347	
348	export interface RubricCombineResult {
349	  judgeMean: number; // 0-10
350	  staticTotal: number; // 0-10
351	  combined: number; // 0-100
352	  grade: string;
353	  summary: string;
354	}
355	
356	const JUDGE_WEIGHT = 0.7;
357	const STATIC_WEIGHT = 0.3;
358	
359	export function combineJudgesAndStatic(
360	  judges: JudgeResult[],
361	  staticScore: StaticScore,
362	  brief: { answers: { audience: string; goal: string } } | null,
363	): RubricCombineResult {
364	  // Mean across judges, with a hard penalty for any judge below 4.
365	  const mean =
366	    judges.length > 0
367	      ? judges.reduce((s, j) => s + j.score, 0) / judges.length
368	      : 5;
369	  const lowJudges = judges.filter((j) => j.score < 4).length;
370	  const lowPenalty = lowJudges * 0.4; // each low judge drags the mean
371	  const judgeMean = clamp(1, 10, mean - lowPenalty);
372	
373	  const staticTotal = staticScore.total;
374	
375	  // Combined score on a 0-10 scale, then mapped to 0-100 with a curve
376	  // designed to be brutal. Most drafts should land in the 40-65 range;
377	  // a 90+ is reserved for genuinely excellent work.
378	  const combinedTen = judgeMean * JUDGE_WEIGHT + staticTotal * STATIC_WEIGHT;
379	  const combinedHundred = brutalCurve(combinedTen * 10);
380	  const grade = letterGrade(combinedHundred);
381	
382	  return {
383	    judgeMean,
384	    staticTotal,
385	    combined: Math.round(combinedHundred),
386	    grade,
387	    summary: buildSummary(judges, staticScore, combinedHundred, brief),
388	  };
389	}
390	
391	/**
392	 * The brutal curve. We compress the 60-80 band and stretch the
393	 * 90+ band so that only really strong work gets there. This is by
394	 * design — Twyne is for writers who want editorial pressure, not for
395	 * a self-esteem mirror.
396	 */
397	function brutalCurve(rawHundred: number): number {
398	  // Anchor the curve at these points:
399	  //   50 raw  →  50 final (a C-grade draft stays a C)
400	  //   60 raw  →  58
401	  //   70 raw  →  67
402	  //   80 raw  →  76
403	  //   90 raw  →  86
404	  //   95 raw  →  93
405	  //  100 raw  → 100
406	  if (rawHundred <= 50) return rawHundred;
407	  if (rawHundred >= 95) return 50 + (rawHundred - 50) * 1.4;
408	  // Linear in 50-95 band
