  return PROVIDER_METAS.find((m) => m.type === type);
}

function providerModelOptions(provider: AiProviderConfig): string[] {
  return Array.from(
    new Set(
      [
        ...(provider.availableModels ?? []),
        provider.defaultModel,
        ...(providerMetaFor(provider.type)?.defaultModels ?? []),
      ].filter(Boolean),
    ),
  );
}

