 */
async function runPlainLlm(
  provider: ProviderConfig,
  system: string,
  user: string,
  maxTokens: number,
): Promise<string> {
  const gen = async (prompt: string) =>
    generateText({
      model: provider.model,
      system,
      prompt,
      temperature: 0.4,
      maxOutputTokens: maxTokens,
    });
  const { text } = await gen(user);
