import { component$, useStore, useVisibleTask$, $ } from "@builder.io/qwik";
import { Link } from "@builder.io/qwik-city";
import { useConvexClient } from "../../utils/convex-context";
import { api } from "../../../convex/_generated/api";
import type { ProjectBrief } from "../../types";
import { loadDraftText, summarizeBrief } from "../../utils/anti-tabula-rasa";
import {
  scoreStaticFeatures,
  combineJudgesAndStatic,
  type StaticScore,
  type JudgeResult,
} from "../../utils/rubric";
import {
  loadRubricResultFromIdb,
  saveRubricResultToIdb,
  loadAiSettingsFromIdb,
} from "../../utils/idb";
import type { AiSettings } from "../../types";
import {
  hasConfiguredAiProvider,
  runClientJudge,
  normalizeAiSettings,
} from "../../utils/ai-client";
import { draftReadiness, MIN_RUBRIC_WORDS } from "../../utils/draft-thresholds";

interface RubricStore {
  result: RubricResult | null;
  isAnalyzing: boolean;
  error: string | null;
  judges: JudgeResult[];
  static: StaticScore | null;
  brief: ProjectBrief | null;
  aiSettings: AiSettings | null;
}

interface RubricCriterion {
  id: string;
  label: string;
  description: string;
  score: number;
  maxScore: number;
  feedback: string;
}

interface RubricResult {
  criteria: RubricCriterion[];
  overallScore: number;
  overallGrade: string;
  summary: string;
  timestamp: number;
  judges: JudgeResult[];
  staticScore: StaticScore;
}

interface RubricPanelProps {
  brief: ProjectBrief | null;
}

export const RubricPanel = component$(({ brief }: RubricPanelProps) => {
  const clientSig = useConvexClient();
  const store = useStore<RubricStore>({
    result: null,
    isAnalyzing: false,
    error: null,
    judges: [],
    static: null,
    brief: null,
    aiSettings: null,
  });

