                class={`flex-shrink-0 w-20 h-20 flex items-center justify-center ${getGradeColor(store.result.overallGrade)}`}
                role="img"
                aria-label={`Overall grade ${store.result.overallGrade}, ${store.result.overallScore} of 100`}
                style={{
